        if (pci_dev->device_id == VIRTIO_DEV_BLOCK) {
            // Read BAR0 to get I/O base
            uint32_t bar0 = oo_pci_read_config_32(pci_dev->bus, pci_dev->dev, pci_dev->func, 0x10);
