    unsigned char byte_pieces[512];
} Tokenizer;

// ----------------------------------------------------------------------------
// Memory Management
// ----------------------------------------------------------------------------

static UINT8* heap_memory = NULL;
static UINTN heap_size = 100 * 1024 * 1024;
static UINTN heap_offset = 0;

void* simple_malloc(UINTN size) {
    if (heap_memory == NULL) {
        EFI_STATUS Status = uefi_call_wrapper(BS->AllocatePool, 3,
            EfiLoaderData, heap_size, (void**)&heap_memory);
        if (EFI_ERROR(Status)) return NULL;
        heap_offset = 0;
    }

    size = (size + 15) & ~15;
    if (heap_offset + size > heap_size) return NULL;

    void* ptr = heap_memory + heap_offset;
    heap_offset += size;

    for (UINTN i = 0; i < size; i++) {
        ((UINT8*)ptr)[i] = 0;
    }

    return ptr;
}

void simple_memcpy(void* dst, const void* src, UINTN n) {
    UINT8* d = (UINT8*)dst;
    const UINT8* s = (const UINT8*)src;
    for (UINTN i = 0; i < n; i++) {
        d[i] = s[i];
    }
}

// ----------------------------------------------------------------------------
// HIGH-QUALITY Math Functions (ARM Optimized Routines)
// ----------------------------------------------------------------------------

static inline uint32_t asuint(float f) {
    union { float f; uint32_t i; } u = {f};
    return u.i;
}

static inline uint64_t asuint64(double f) {
    union { double f; uint64_t i; } u = {f};
    return u.i;
}

static inline double asdouble(uint64_t i) {
    union { uint64_t i; double f; } u = {i};
    return u.f;
}

// Fast sqrt (Newton-Raphson)
float sqrtf(float x) {
    if (x <= 0.0f) return 0.0f;
    float guess = x;
    for (int i = 0; i < 5; i++) {
        if (guess == 0.0f) return 0.0f;
        guess = (guess + x / guess) / 2.0f;
    }
    return guess;
}

// High-quality expf (ARM Optimized)
float expf(float x) {
    const double shift = 0x1.8p52;

    if (x < -0x1.9fe368p6f) return 0.0f;
    if (x > 0x1.62e42ep6f) {
        union { uint32_t i; float f; } u = {0x7f800000};
        return u.f;
    }

    int N = 32;
    double z = 0x1.71547652b82fep+0 * N * x;
    double kd = z + shift;

    union { double f; uint64_t i; } u_shift = {kd};
    uint64_t ki = u_shift.i;
    kd -= shift;
    double r = z - kd;

    static const uint64_t T[32] = {
        0x3ff0000000000000, 0x3fefd9b0d3158574, 0x3fefb5586cf9890f, 0x3fef9301d0125b51,
        0x3fef72b83c7d517b, 0x3fef54873168b9aa, 0x3fef387a6e756238, 0x3fef1e9df51fdee1,
        0x3fef06fe0a31b715, 0x3feef1a7373aa9cb, 0x3feedea64c123422, 0x3feece086061892d,
        0x3feebfdad5362a27, 0x3feeb42b569d4f82, 0x3feeab07dd485429, 0x3feea47eb03a5585,
        0x3feea09e667f3bcd, 0x3fee9f75e8ec5f74, 0x3feea11473eb0187, 0x3feea589994cce13,
        0x3feeace5422aa0db, 0x3feeb737b0cdc5e5, 0x3feec49182a3f090, 0x3feed503b23e255d,
        0x3feee89f995ad3ad, 0x3feeff76f2fb5e47, 0x3fef199bdd85529c, 0x3fef3720dcef9069,
        0x3fef5818dcfba487, 0x3fef7c97337b9b5f, 0x3fefa4afa2a490da, 0x3fefd0765b6e4540,
    };

    union { uint64_t i; double f; } d = {T[ki % N] + (ki << 47)};

    double p0 = 0x1.c6af84b912394p-5 / N / N / N;
    double p1 = 0x1.ebfce50fac4f3p-3 / N / N;
    double p2 = 0x1.62e42ff0c52d6p-1 / N;
    double y = p2 * r + 1;
    y = (p0 * r + p1) * (r * r) + y;
    y = y * d.f;
    return (float)y;
}

// High-quality powf (ARM Optimized) - CORRECT IMPLEMENTATION
float powf(float base, float exp) {
    // Handle special cases
    if (base == 0.0f) return 0.0f;
    if (exp == 0.0f) return 1.0f;
    if (base == 1.0f) return 1.0f;
    if (base < 0.0f) return 0.0f; // Simplified for LLM use

    // pow(a,b) = exp(b * log(a))
    // Use high-quality log approximation
    float logbase;

    // Extract exponent
    union { float f; uint32_t i; } u = {base};
    int e = ((u.i >> 23) & 0xFF) - 127;
    u.i = (u.i & 0x007FFFFF) | 0x3F800000;
    float mantissa = u.f;

    // log(base) = e*log(2) + log(mantissa)
    // log(mantissa) for mantissa in [1,2]
    float m = mantissa - 1.0f;
    float m2 = m * m;
    float m3 = m2 * m;
    logbase = e * 0.69314718f + m - m2/2.0f + m3/3.0f;

    // Return exp(exp * log(base))
    return expf(exp * logbase);
}

// High-quality sinf and cosf
float sinf(float x) {
    // Reduce to [-pi, pi]
    const float pi = 3.14159265358979323846f;
    const float pi2 = 6.28318530717958647692f;

    // Range reduction
    float k = x / pi2;
    k = k - (int)k; // Fractional part
    if (k < 0.0f) k += 1.0f;
    x = k * pi2;

    // Map to [-pi, pi]
    if (x > pi) x -= pi2;

    // Taylor series: sin(x) ≈ x - x^3/6 + x^5/120
    float x2 = x * x;
    float x3 = x2 * x;
    float x5 = x3 * x2;
    return x - x3/6.0f + x5/120.0f;
}

float cosf(float x) {
    const float pi_2 = 1.57079632679489661923f;
    return sinf(x + pi_2);
}

// ----------------------------------------------------------------------------
// Neural Net Building Blocks
// ----------------------------------------------------------------------------

void rmsnorm(float* o, float* x, float* weight, int size) {
    float ss = 0.0f;
    for (int j = 0; j < size; j++) {
        ss += x[j] * x[j];
    }
    ss /= size;
    ss += 1e-5f;
    ss = 1.0f / sqrtf(ss);

    for (int j = 0; j < size; j++) {
        o[j] = weight[j] * (ss * x[j]);
    }
}

void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) {
        if (x[i] > max_val) max_val = x[i];
    }

    float sum = 0.0f;
    for (int i = 0; i < size; i++) {
        x[i] = expf(x[i] - max_val);
        sum += x[i];
    }

    for (int i = 0; i < size; i++) {
        x[i] /= sum;
    }
}

void matmul(float* xout, float* x, float* w, int n, int d) {
    for (int i = 0; i < d; i++) {
        float val = 0.0f;
        for (int j = 0; j < n; j++) {
            val += w[i * n + j] * x[j];
        }
        xout[i] = val;
    }
}

// ----------------------------------------------------------------------------
// Transformer Forward Pass
// ----------------------------------------------------------------------------

float* forward(Transformer* transformer, int token, int pos) {
    Config* p = &transformer->config;
    TransformerWeights* w = &transformer->weights;
    RunState* s = &transformer->state;
    float *x = s->x;
    int dim = p->dim;
    int kv_dim = (p->dim * p->n_kv_heads) / p->n_heads;
    int kv_mul = p->n_heads / p->n_kv_heads;
    int hidden_dim = p->hidden_dim;
    int head_size = dim / p->n_heads;

    float* content_row = w->token_embedding_table + token * dim;
    simple_memcpy(x, content_row, dim * sizeof(*x));

    for (int l = 0; l < p->n_layers; l++) {
        rmsnorm(s->xb, x, w->rms_att_weight + l * dim, dim);

        int loff = l * p->seq_len * kv_dim;
        s->k = s->key_cache + loff + pos * kv_dim;
        s->v = s->value_cache + loff + pos * kv_dim;

        matmul(s->q, s->xb, w->wq + l * dim * dim, dim, dim);
        matmul(s->k, s->xb, w->wk + l * dim * kv_dim, dim, kv_dim);
        matmul(s->v, s->xb, w->wv + l * dim * kv_dim, dim, kv_dim);

        // RoPE with FIXED powf
        for (int i = 0; i < dim; i += 2) {
            int head_dim = i % head_size;
            float freq = 1.0f / powf(10000.0f, head_dim / (float)head_size);
            float val = pos * freq;
            float fcr = cosf(val);
            float fci = sinf(val);

            int rotn = i < kv_dim ? 2 : 1;
            for (int v = 0; v < rotn; v++) {
                float* vec = v == 0 ? s->q : s->k;
                float v0 = vec[i];
                float v1 = vec[i + 1];
                vec[i] = v0 * fcr - v1 * fci;
                vec[i + 1] = v0 * fci + v1 * fcr;
            }
        }

        // Multi-head attention
        for (int h = 0; h < p->n_heads; h++) {
            float* q = s->q + h * head_size;
            float* att = s->att + h * p->seq_len;

            for (int t = 0; t <= pos; t++) {
                float* k = s->key_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float score = 0.0f;
                for (int i = 0; i < head_size; i++) {
                    score += q[i] * k[i];
                }
                score /= sqrtf(head_size);
                att[t] = score;
            }

            softmax(att, pos + 1);

            float* xb = s->xb + h * head_size;
            for (int i = 0; i < head_size; i++) xb[i] = 0.0f;

            for (int t = 0; t <= pos; t++) {
                float* v = s->value_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float a = att[t];
                for (int i = 0; i < head_size; i++) {
                    xb[i] += a * v[i];
                }
            }
        }

        matmul(s->xb2, s->xb, w->wo + l * dim * dim, dim, dim);

        for (int i = 0; i < dim; i++) {
            x[i] += s->xb2[i];
        }

        rmsnorm(s->xb, x, w->rms_ffn_weight + l * dim, dim);

        matmul(s->hb, s->xb, w->w1 + l * dim * hidden_dim, dim, hidden_dim);
        matmul(s->hb2, s->xb, w->w3 + l * dim * hidden_dim, dim, hidden_dim);

        for (int i = 0; i < hidden_dim; i++) {
            float val = s->hb[i];
            val *= (1.0f / (1.0f + expf(-val)));
            val *= s->hb2[i];
            s->hb[i] = val;
        }

        matmul(s->xb, s->hb, w->w2 + l * dim * hidden_dim, hidden_dim, dim);

        for (int i = 0; i < dim; i++) {
            x[i] += s->xb[i];
        }
    }

    rmsnorm(x, x, w->rms_final_weight, dim);
    matmul(s->logits, x, w->wcls, p->dim, p->vocab_size);

    return s->logits;
}

// ----------------------------------------------------------------------------
// Model Loading
// ----------------------------------------------------------------------------

EFI_STATUS load_model(Transformer* t, CHAR16* model_path, EFI_HANDLE ImageHandle) {
    EFI_STATUS Status;
    EFI_FILE_IO_INTERFACE *FileSystem;
    EFI_FILE *Root, *File;

    Status = uefi_call_wrapper(BS->LocateProtocol, 3,
        &FileSystemProtocol, NULL, (void**)&FileSystem);
    if (EFI_ERROR(Status)) return Status;

    Status = uefi_call_wrapper(FileSystem->OpenVolume, 2, FileSystem, &Root);
    if (EFI_ERROR(Status)) return Status;

    Status = uefi_call_wrapper(Root->Open, 5, Root, &File, model_path, EFI_FILE_MODE_READ, 0);
    if (EFI_ERROR(Status)) {
        Print(L"ERROR: Cannot open model file %s\r\n", model_path);
        return Status;
    }

    EFI_FILE_INFO *FileInfo;
    UINTN BufferSize = sizeof(EFI_FILE_INFO) + 200;
    FileInfo = (EFI_FILE_INFO*)simple_malloc(BufferSize);
    Status = uefi_call_wrapper(File->GetInfo, 4, File, &GenericFileInfo, &BufferSize, FileInfo);
    if (EFI_ERROR(Status)) {
        uefi_call_wrapper(File->Close, 1, File);
        return Status;
    }

    t->file_size = FileInfo->FileSize;
    Print(L"Model file size: %d bytes\r\n", t->file_size);

    t->data = (float*)simple_malloc(t->file_size);
    if (t->data == NULL) {
        Print(L"ERROR: Cannot allocate %d bytes\r\n", t->file_size);
        uefi_call_wrapper(File->Close, 1, File);
        return EFI_OUT_OF_RESOURCES;
    }

    UINTN read_size = t->file_size;
    Status = uefi_call_wrapper(File->Read, 3, File, &read_size, t->data);
    uefi_call_wrapper(File->Close, 1, File);

    if (EFI_ERROR(Status) || read_size != t->file_size) {
        Print(L"ERROR: Failed to read model\r\n");
        return EFI_DEVICE_ERROR;
    }

    Config* config = (Config*)t->data;
    t->config = *config;

    int shared_weights = t->config.vocab_size > 0 ? 1 : 0;
    if (t->config.vocab_size < 0) {
        t->config.vocab_size = -t->config.vocab_size;
    }

    Print(L"Config: dim=%d, layers=%d, heads=%d, vocab=%d\r\n",
        t->config.dim, t->config.n_layers, t->config.n_heads, t->config.vocab_size);

    float* weights_ptr = t->data + sizeof(Config) / sizeof(float);
    TransformerWeights* w = &t->weights;
    int head_size = t->config.dim / t->config.n_heads;

    w->token_embedding_table = weights_ptr;
    weights_ptr += t->config.vocab_size * t->config.dim;
    w->rms_att_weight = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim;
    w->wq = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim * (t->config.n_heads * head_size);
    w->wk = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim * (t->config.n_kv_heads * head_size);
    w->wv = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim * (t->config.n_kv_heads * head_size);
    w->wo = weights_ptr;
    weights_ptr += t->config.n_layers * (t->config.n_heads * head_size) * t->config.dim;
    w->rms_ffn_weight = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim;
    w->w1 = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim * t->config.hidden_dim;
    w->w2 = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.hidden_dim * t->config.dim;
    w->w3 = weights_ptr;
    weights_ptr += t->config.n_layers * t->config.dim * t->config.hidden_dim;
    w->rms_final_weight = weights_ptr;
    weights_ptr += t->config.dim;
    weights_ptr += t->config.seq_len * head_size / 2;
    weights_ptr += t->config.seq_len * head_size / 2;
    w->wcls = shared_weights ? w->token_embedding_table : weights_ptr;

    RunState* s = &t->state;
    int kv_dim = (t->config.dim * t->config.n_kv_heads) / t->config.n_heads;

    s->x = (float*)simple_malloc(t->config.dim * sizeof(float));
    s->xb = (float*)simple_malloc(t->config.dim * sizeof(float));
    s->xb2 = (float*)simple_malloc(t->config.dim * sizeof(float));
    s->hb = (float*)simple_malloc(t->config.hidden_dim * sizeof(float));
    s->hb2 = (float*)simple_malloc(t->config.hidden_dim * sizeof(float));
    s->q = (float*)simple_malloc(t->config.dim * sizeof(float));
    s->key_cache = (float*)simple_malloc(t->config.n_layers * t->config.seq_len * kv_dim * sizeof(float));
    s->value_cache = (float*)simple_malloc(t->config.n_layers * t->config.seq_len * kv_dim * sizeof(float));
    s->att = (float*)simple_malloc(t->config.n_heads * t->config.seq_len * sizeof(float));
    s->logits = (float*)simple_malloc(t->config.vocab_size * sizeof(float));

    if (!s->x || !s->xb || !s->xb2 || !s->hb || !s->hb2 || !s->q ||
        !s->key_cache || !s->value_cache || !s->att || !s->logits) {
        Print(L"ERROR: Failed to allocate buffers\r\n");
        return EFI_OUT_OF_RESOURCES;
    }

    Print(L"Model loaded successfully\r\n");
    return EFI_SUCCESS;
}

// ----------------------------------------------------------------------------
// Tokenizer (CORRECT from llama2_efi.c)
// ----------------------------------------------------------------------------

EFI_STATUS load_tokenizer(Tokenizer* t, CHAR16* tokenizer_path, int vocab_size) {
    EFI_STATUS Status;
    EFI_FILE_IO_INTERFACE *FileSystem;
    EFI_FILE *Root, *File;

    Status = uefi_call_wrapper(BS->LocateProtocol, 3,
        &FileSystemProtocol, NULL, (void**)&FileSystem);
    if (EFI_ERROR(Status)) return Status;

    Status = uefi_call_wrapper(FileSystem->OpenVolume, 2, FileSystem, &Root);
    if (EFI_ERROR(Status)) return Status;

    Status = uefi_call_wrapper(Root->Open, 5, Root, &File, tokenizer_path, EFI_FILE_MODE_READ, 0);
    if (EFI_ERROR(Status)) {
        Print(L"ERROR: Cannot open tokenizer %s\r\n", tokenizer_path);
        return Status;
    }

    UINTN read_size = sizeof(int);
    Status = uefi_call_wrapper(File->Read, 3, File, &read_size, &t->max_token_length);
    if (EFI_ERROR(Status)) {
        uefi_call_wrapper(File->Close, 1, File);
        return Status;
    }

    for (int i = 0; i < 256; i++) {
        t->byte_pieces[i * 2] = (unsigned char)i;
        t->byte_pieces[i * 2 + 1] = '\0';
    }

    t->vocab_size = vocab_size;
    t->vocab = (char**)simple_malloc(vocab_size * sizeof(char*));
    t->vocab_scores = (float*)simple_malloc(vocab_size * sizeof(float));

    if (!t->vocab || !t->vocab_scores) {
        uefi_call_wrapper(File->Close, 1, File);
        return EFI_OUT_OF_RESOURCES;
    }

    for (int i = 0; i < vocab_size; i++) {
        read_size = sizeof(float);
        Status = uefi_call_wrapper(File->Read, 3, File, &read_size, &t->vocab_scores[i]);
        if (EFI_ERROR(Status)) break;

        int len;
        read_size = sizeof(int);
        Status = uefi_call_wrapper(File->Read, 3, File, &read_size, &len);
        if (EFI_ERROR(Status)) break;

        t->vocab[i] = (char*)simple_malloc(len + 1);
        if (!t->vocab[i]) {
            Status = EFI_OUT_OF_RESOURCES;
            break;
        }

        read_size = len;
        Status = uefi_call_wrapper(File->Read, 3, File, &read_size, t->vocab[i]);
        if (EFI_ERROR(Status)) break;

        t->vocab[i][len] = '\0';
    }

    uefi_call_wrapper(File->Close, 1, File);

    if (EFI_ERROR(Status)) {
        Print(L"ERROR: Failed to load tokenizer\r\n");
        return Status;
    }

    Print(L"Tokenizer loaded: %d tokens, max_len=%d\r\n", vocab_size, t->max_token_length);
    return EFI_SUCCESS;
}

char* decode_token(Tokenizer* t, int prev_token, int token) {
    if (token < 0 || token >= t->vocab_size) {
        return "<?>";
    }

    char* piece = t->vocab[token];

    if (prev_token == 1 && piece[0] == ' ') {
        piece++;
    }

    unsigned char byte_val;
    if (piece[0] == '<' && piece[1] == '0' && piece[2] == 'x' && piece[5] == '>') {
        byte_val = 0;
        for (int i = 0; i < 2; i++) {
            byte_val *= 16;
            char c = piece[3 + i];
            if (c >= '0' && c <= '9') {
                byte_val += c - '0';
            } else if (c >= 'A' && c <= 'F') {
                byte_val += c - 'A' + 10;
            } else if (c >= 'a' && c <= 'f') {
                byte_val += c - 'a' + 10;
            }
        }
        piece = (char*)t->byte_pieces + byte_val * 2;
    }

    return piece;
}

void print_token(char* token_str) {
    if (token_str == NULL) return;

    for (int i = 0; i < 64 && token_str[i] != '\0'; i++) {
        unsigned char c = (unsigned char)token_str[i];
        if (c >= 32 && c < 127) {
            Print(L"%c", (CHAR16)c);
        }
    }
}

// ----------------------------------------------------------------------------
// Sampling
// ----------------------------------------------------------------------------

int sample_argmax(float* logits, int vocab_size) {
    int max_i = 0;
    float max_val = logits[0];
    for (int i = 1; i < vocab_size; i++) {
        if (logits[i] > max_val) {
            max_i = i;
            max_val = logits[i];
        }
    }
    return max_i;
}

// ----------------------------------------------------------------------------
// Generation
// ----------------------------------------------------------------------------

void generate(Transformer* transformer, Tokenizer* tokenizer, int steps) {
    Print(L"\r\n=== Generation (%d steps) ===\r\n\r\n", steps);

    int token = 1;
    int pos = 0;

    while (pos < steps) {
        float* logits = forward(transformer, token, pos);
        int next = sample_argmax(logits, transformer->config.vocab_size);
        pos++;

        if (next == 1 || next == 2) break;

        char* piece = decode_token(tokenizer, token, next);
        print_token(piece);

        token = next;
    }

    Print(L"\r\n\r\n=== Complete ===\r\n");
}

// ----------------------------------------------------------------------------
// Main Entry Point
// ----------------------------------------------------------------------------

EFI_STATUS efi_main(EFI_HANDLE ImageHandle, EFI_SYSTEM_TABLE *SystemTable) {
    InitializeLib(ImageHandle, SystemTable);

    Print(L"\r\n");
    Print(L"========================================\r\n");
    Print(L"  Llama2 Fixed - Bare-Metal Inference\r\n");
    Print(L"========================================\r\n");
    Print(L"\r\n");

    Transformer transformer;
    for (int i = 0; i < sizeof(Transformer); i++) {
        ((char*)&transformer)[i] = 0;
    }

    Print(L"Loading model...\r\n");
    EFI_STATUS Status = load_model(&transformer, L"stories15M.bin", ImageHandle);
    if (EFI_ERROR(Status)) {
        Print(L"FATAL: Model load failed (Status: %d)\r\n", Status);
        return Status;
    }

    Tokenizer tokenizer;
    for (int i = 0; i < sizeof(Tokenizer); i++) {
        ((char*)&tokenizer)[i] = 0;
    }

    Print(L"Loading tokenizer...\r\n");
    Status = load_tokenizer(&tokenizer, L"tokenizer.bin", transformer.config.vocab_size);
    if (EFI_ERROR(Status)) {
        Print(L"FATAL: Tokenizer load failed (Status: %d)\r\n", Status);
        return Status;
    }

    generate(&transformer, &tokenizer, 50);

    Print(L"\r\nPress any key to exit...\r\n");
    WaitForSingleEvent(ST->ConIn->WaitForKey, 0);

    return EFI_SUCCESS;
}
