typedef struct {
    int dim, hidden_dim, n_layers, n_heads, n_kv_heads, vocab_size, seq_len;
} Config;

typedef struct {
    float* token_embedding_table;
    float* rms_att_weight;
    float* wq, *wk, *wv, *wo;
    float* rms_ffn_weight;
    float* w1, *w2, *w3;
    float* rms_final_weight;
    float* wcls;
} TransformerWeights;

typedef struct {
    float *x, *xb, *xb2, *hb, *hb2, *q, *k, *v, *att, *logits;
    float *key_cache, *value_cache;
} RunState;

typedef struct {
    char** vocab;
    float* vocab_scores;
    int vocab_size;
    int max_token_length;
} Tokenizer;

// ============================================================================
// FORWARD PASS (simplified - single layer at a time)
// ============================================================================

void transformer_forward(RunState* s, TransformerWeights* w, Config* p, int token, int pos) {
    int dim = p->dim;
    int hidden_dim = p->hidden_dim;
    int n_layers = p->n_layers;
    int n_heads = p->n_heads;
    int head_size = dim / n_heads;
    int kv_dim = dim;
    int kv_mul = n_heads / p->n_kv_heads;

    // Copy token embedding into x
    float* content_row = w->token_embedding_table + token * dim;
    for (int i = 0; i < dim; i++) s->x[i] = content_row[i];

    // Forward through all layers
    for (int l = 0; l < n_layers; l++) {
        // Attention rmsnorm
        rmsnorm(s->xb, s->x, w->rms_att_weight + l * dim, dim);

        // QKV matmuls
        matmul(s->q, s->xb, w->wq + l * dim * dim, dim, dim);
        matmul(s->k, s->xb, w->wk + l * dim * kv_dim, dim, kv_dim);
        matmul(s->v, s->xb, w->wv + l * dim * kv_dim, dim, kv_dim);

        // Store KV in cache
        int loff = l * SEQ_LEN * kv_dim;
        float* key_cache_row = s->key_cache + loff + pos * kv_dim;
        float* value_cache_row = s->value_cache + loff + pos * kv_dim;
        for (int i = 0; i < kv_dim; i++) {
            key_cache_row[i] = s->k[i];
            value_cache_row[i] = s->v[i];
        }

        // Multihead attention
        for (int h = 0; h < n_heads; h++) {
            float* q_h = s->q + h * head_size;
            float* att_h = s->att + h * SEQ_LEN;

            // Attention scores
            for (int t = 0; t <= pos; t++) {
                float* k_t = s->key_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float score = 0.0f;
                for (int i = 0; i < head_size; i++) score += q_h[i] * k_t[i];
                score /= fast_sqrt(head_size);
                att_h[t] = score;
            }

            // Softmax
            softmax(att_h, pos + 1);

            // Weighted sum
            float* xb_h = s->xb + h * head_size;
            for (int i = 0; i < head_size; i++) xb_h[i] = 0.0f;
            for (int t = 0; t <= pos; t++) {
                float* v_t = s->value_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float a = att_h[t];
                for (int i = 0; i < head_size; i++) xb_h[i] += a * v_t[i];
            }
        }

        // Output projection
        matmul(s->xb2, s->xb, w->wo + l * dim * dim, dim, dim);

        // Residual connection
        for (int i = 0; i < dim; i++) s->x[i] += s->xb2[i];

        // FFN rmsnorm
        rmsnorm(s->xb, s->x, w->rms_ffn_weight + l * dim, dim);

        // FFN
        matmul(s->hb, s->xb, w->w1 + l * dim * hidden_dim, dim, hidden_dim);
        matmul(s->hb2, s->xb, w->w3 + l * dim * hidden_dim, dim, hidden_dim);

        // SwiGLU
        for (int i = 0; i < hidden_dim; i++) {
            float val = s->hb[i];
            val *= (1.0f / (1.0f + fast_exp(-val)));
            val *= s->hb2[i];
            s->hb[i] = val;
        }

        matmul(s->xb, s->hb, w->w2 + l * dim * hidden_dim, hidden_dim, dim);

        // Residual
        for (int i = 0; i < dim; i++) s->x[i] += s->xb[i];
    }

    // Final rmsnorm
    rmsnorm(s->x, s->x, w->rms_final_weight, dim);

    // Classifier
    matmul(s->logits, s->x, w->wcls, dim, p->vocab_size);
}

// ============================================================================
// SAMPLING
// ============================================================================

int sample(float* probabilities, int n) {
    // Greedy sampling for now (take argmax)
    int max_i = 0;
    float max_p = probabilities[0];
    for (int i = 1; i < n; i++) {
        if (probabilities[i] > max_p) {
            max_p = probabilities[i];
            max_i = i;
        }
    }
    return max_i;
}

// ============================================================================
// TOKENIZER
// ============================================================================

static int my_strcmp(const char* s1, const char* s2) {
    while (*s1 && (*s1 == *s2)) {
        s1++; s2++;
    }
    return *(unsigned char*)s1 - *(unsigned char*)s2;
}

static int my_strlen(const char* s) {
    int len = 0;
    while (s[len]) len++;
    return len;
}

int str_lookup(char* str, char** vocab, int vocab_size) {
    for (int i = 0; i < vocab_size; i++) {
        if (vocab[i] && my_strcmp(str, vocab[i]) == 0) {
            return i;
        }
    }
    return -1;
}

void encode(char* text, int* tokens, int* n_tokens, Tokenizer* t) {
    *n_tokens = 0;

    // Add BOS
    tokens[(*n_tokens)++] = 1;

    // Simple word-by-word encoding
    char* str = text;
    while (*str != '\0') {
        // Skip spaces
        while (*str == ' ') str++;
        if (*str == '\0') break;

        // Find word end
        char* word_start = str;
        while (*str != '\0' && *str != ' ') str++;

        // Extract word
        int word_len = str - word_start;
        char word[256];
        for (int i = 0; i < word_len && i < 255; i++) word[i] = word_start[i];
        word[word_len] = '\0';

        // Lookup
        int id = str_lookup(word, t->vocab, t->vocab_size);
        if (id >= 0) {
            tokens[(*n_tokens)++] = id;
        }
    }
}

