            }
        }

        // Output projection
        matmul(s->xb2, s->xb, w->wo + l*dim*dim, dim, dim);

        // Residual
        for (int i = 0; i < dim; i++) {
            s->x[i] += s->xb2[i];
        }

        // FFN RMSNorm
        rmsnorm(s->xb, s->x, w->rms_ffn_weight + l*dim, dim);

        // FFN
        matmul(s->hb, s->xb, w->w1 + l*dim*hidden_dim, dim, hidden_dim);
        matmul(s->hb2, s->xb, w->w3 + l*dim*hidden_dim, dim, hidden_dim);

        // SwiGLU
        for (int i = 0; i < hidden_dim; i++) {
            float val = s->hb[i];
            val *= (1.0f / (1.0f + fast_exp(-val)));
            s->hb[i] = val * s->hb2[i];
        }

        matmul(s->xb, s->hb, w->w2 + l*dim*hidden_dim, hidden_dim, dim);

        // Residual
        for (int i = 0; i < dim; i++) {
            s->x[i] += s->xb[i];
        }
    }

    // Final RMSNorm
    rmsnorm(s->x, s->x, w->rms_final_weight, dim);

    // Classifier
    matmul(s->logits, s->x, w->wcls, dim, p->vocab_size);
}

int sample(float* logits, int n) {
    int max_i = 0;
    float max_val = logits[0];
    for (int i = 1; i < n; i++) {
        if (logits[i] > max_val) {
            max_val = logits[i];
            max_i = i;
        }
    }
    return max_i;
}

// ============================================================================
// TOKENIZER
// ============================================================================

static int my_strcmp(const char* s1, const char* s2) {
    while (*s1 && (*s1 == *s2)) {
        s1++; s2++;
    }
    return *(unsigned char*)s1 - *(unsigned char*)s2;
}

static int my_strlen(const char* s) {
    int len = 0;
    while (s[len]) len++;
    return len;
}

int str_lookup(char* str, char** vocab, int vocab_size) {
    for (int i = 0; i < vocab_size; i++) {
        if (vocab[i] && my_strcmp(str, vocab[i]) == 0) {
            return i;
        }
    }
    return -1;
}

void encode(char* text, int* tokens, int* n_tokens, Tokenizer* t) {
    *n_tokens = 0;

    // Add BOS
    tokens[(*n_tokens)++] = 1;

    // Simple word-by-word encoding
    char* str = text;
    char piece[256];
    int piece_idx = 0;

    while (*str) {
        if (*str == ' ' || *str == '\n' || *str == '\t') {
            if (piece_idx > 0) {
                piece[piece_idx] = 0;
                int id = str_lookup(piece, t->vocab, t->vocab_size);
                if (id >= 0) tokens[(*n_tokens)++] = id;
                piece_idx = 0;
            }
            str++;
        } else {
            piece[piece_idx++] = *str++;
            if (piece_idx >= 255) {
                piece[piece_idx] = 0;
                int id = str_lookup(piece, t->vocab, t->vocab_size);
                if (id >= 0) tokens[(*n_tokens)++] = id;
                piece_idx = 0;
            }
        }
    }

    // Last piece
    if (piece_idx > 0) {
        piece[piece_idx] = 0;
        int id = str_lookup(piece, t->vocab, t->vocab_size);
        if (id >= 0) tokens[(*n_tokens)++] = id;
    }
}

// ============================================================================
// KEYBOARD INPUT
// ============================================================================

void read_user_input(CHAR16* buffer, int max_len) {
    int pos = 0;
    EFI_INPUT_KEY Key;

    while (pos < max_len - 1) {
        // Wait for key
        UINTN index;
        uefi_call_wrapper(BS->WaitForEvent, 3, 1, &ST->ConIn->WaitForKey, &index);
        uefi_call_wrapper(ST->ConIn->ReadKeyStroke, 2, ST->ConIn, &Key);

        if (Key.UnicodeChar == 0x000D) {  // Enter
            buffer[pos] = 0;
            Print(L"\r\n");
            break;
        } else if (Key.UnicodeChar == 0x0008) {  // Backspace
            if (pos > 0) {
                pos--;
                Print(L"\b \b");
            }
        } else if (Key.UnicodeChar >= 32 && Key.UnicodeChar < 127) {
            buffer[pos++] = Key.UnicodeChar;
            Print(L"%c", Key.UnicodeChar);
        }
    }

    buffer[pos] = 0;
}

void char16_to_char(char* dest, CHAR16* src, int max_len) {
    int i;
    for (i = 0; i < max_len - 1 && src[i]; i++) {
        dest[i] = (char)src[i];
    }
    dest[i] = 0;
}

