    int pos = n_prompt_tokens - 1;

    for (int step = 0; step < MAX_TOKENS; step++) {
        // Forward pass
        transformer_forward(&state, &weights, &config, token, pos);

        // Sample next token
        softmax(state.logits, config.vocab_size);
