        // Print token
        if (next == 1) break;  // EOS
        if (tokenizer.vocab[next]) {
            char* piece = tokenizer.vocab[next];
            CHAR16 wpiece[256];
            int i;
            for (i = 0; piece[i] && i < 255; i++) {
                wpiece[i] = (CHAR16)piece[i];
            }
            wpiece[my_strlen(piece)] = 0;
            Print(L"%s", wpiece);
        }

        // Next iteration
        token = next;
