void encode(char* text, int* tokens, int* n_tokens, Tokenizer* t) {
    *n_tokens = 0;

    // Add BOS
    tokens[(*n_tokens)++] = 1;

    // Character-by-character encoding with greedy longest match
    char* str = text;

    while (*str) {
        // Try to match longest possible token
        int best_id = -1;
        int best_len = 0;

        // Try different lengths starting from longest
        for (int len = 64; len > 0; len--) {
            if (str[len-1] == '\0') continue;

            char piece[65];
            int i;
            for (i = 0; i < len && str[i]; i++) {
                piece[i] = str[i];
            }
            piece[i] = '\0';

            int id = str_lookup(piece, t->vocab, t->vocab_size);
            if (id >= 0) {
                best_id = id;
                best_len = i;
                break;
            }
        }

        if (best_id >= 0) {
            tokens[(*n_tokens)++] = best_id;
            str += best_len;
        } else {
            // Single character fallback
            char single[2];
            single[0] = *str;
            single[1] = '\0';
            int id = str_lookup(single, t->vocab, t->vocab_size);
            if (id >= 0) {
                tokens[(*n_tokens)++] = id;
            }
            str++;
        }

        // Safety check
        if (*n_tokens >= 255) break;
    }
}

