        }

        // Echo prompt
        for (int i = 1; i < n_prompt_tokens; i++) {
            if (tokenizer.vocab[prompt_tokens[i]]) {
                char* piece = tokenizer.vocab[prompt_tokens[i]];

                // Skip special tokens
                if (piece[0] == '<' && my_strlen(piece) > 2) {
                    int len = my_strlen(piece);
                    if (piece[len-1] == '>') continue;
                }

                CHAR16 wpiece[256];
                int j;
                for (j = 0; piece[j] && j < 255; j++) {
                    wpiece[j] = (CHAR16)piece[j];
                }
                wpiece[my_strlen(piece)] = 0;
                Print(L"%s", wpiece);
            }
        }

        // Start generation from last prompt token
        int next;
        int token = prompt_tokens[n_prompt_tokens - 1];
        int pos = n_prompt_tokens;

        for (int step = 0; step < MAX_TOKENS; step++) {
            // Forward pass
            transformer_forward(&state, &weights, &config, token, pos);

            // Sample next token
            softmax(state.logits, config.vocab_size);
            next = sample(state.logits, config.vocab_size);

            // Check for EOS
            if (next == 1) break;  // EOS

            // Print token (with filtering)
            int should_print = 1;

            if (next >= 0 && next < config.vocab_size && tokenizer.vocab[next]) {
                char* piece = tokenizer.vocab[next];
                int len = my_strlen(piece);

                // Only skip clear special tokens like <unk>
                if (len >= 5 && piece[0] == '<' && piece[len-1] == '>') {
                    // Check for specific bad tokens
                    if (my_strcmp(piece, "<unk>") == 0 || 
                        my_strcmp(piece, "<s>") == 0 || 
                        my_strcmp(piece, "</s>") == 0) {
                        should_print = 0;
                    }
                }

                // Skip empty tokens
                if (len == 0) should_print = 0;

                if (should_print) {
                    CHAR16 wpiece[256];
                    int i;
                    for (i = 0; i < len && i < 255; i++) {
                        wpiece[i] = (CHAR16)piece[i];
                    }
                    wpiece[len] = 0;
                    Print(L"%s", wpiece);
                }
            }

            // Next iteration - ALWAYS advance
            token = next;
            pos++;
        }

        Print(L"\r\n\r\n");
    }

    Print(L"Press any key to exit...\r\n");
    EFI_INPUT_KEY Key;
    UINTN index;
    uefi_call_wrapper(BS->WaitForEvent, 3, 1, &ST->ConIn->WaitForKey, &index);
    uefi_call_wrapper(ST->ConIn->ReadKeyStroke, 2, ST->ConIn, &Key);

    return EFI_SUCCESS;
