    int hidden_dim;
    int n_layers;
    int n_heads;
    int n_kv_heads;
    int vocab_size;
    int seq_len;
} Config;

// ============================================================================
// HEAP ALLOCATOR
// ============================================================================
static UINTN g_heap_base = 0;
static UINTN g_heap_offset = 0;
static UINTN g_heap_size = 0;

void* simple_alloc(UINTN size) {
    if (g_heap_offset + size > g_heap_size) return NULL;
    void* ptr = (void*)(g_heap_base + g_heap_offset);
    g_heap_offset += ((size + 15) & ~15);
    return ptr;
}

// ============================================================================
// MATH FUNCTIONS
// ============================================================================
float fast_sqrt(float x) {
    if (x <= 0.0f) return 0.0f;
    float xhalf = 0.5f * x;
    int i = *(int*)&x;
    i = 0x5f375a86 - (i >> 1);
    x = *(float*)&i;
    x = x * (1.5f - xhalf * x * x);
    x = x * (1.5f - xhalf * x * x);
    return 1.0f / x;
}

float fast_exp(float x) {
    if (x < -10.0f) return 0.0f;
    if (x > 10.0f) return 22026.0f;
    float result = 1.0f + x;
    float term = x;
    for (int i = 2; i < 10; i++) {
        term *= x / i;
        result += term;
    }
    return result;
}

// ============================================================================
// TRANSFORMER WEIGHTS
// ============================================================================
typedef struct {
    float* token_embedding_table;
    float* rms_att_weight;
    float* wq;
    float* wk;
    float* wv;
    float* wo;
    float* rms_ffn_weight;
    float* w1;
    float* w2;
    float* w3;
    float* rms_final_weight;
    float* wcls;
} TransformerWeights;

// ============================================================================
// RUN STATE
// ============================================================================
typedef struct {
    float* x;
    float* xb;
    float* xb2;
    float* hb;
    float* hb2;
    float* q;
    float* k;
    float* v;
    float* att;
    float* logits;
    float* key_cache;
    float* value_cache;
} RunState;

// ============================================================================
// RMSNORM
// ============================================================================
void rmsnorm(float* o, float* x, float* weight, int size) {
    float ss = 0.0f;
    for (int j = 0; j < size; j++) ss += x[j] * x[j];
    ss /= size;
    ss += 1e-5f;
    ss = 1.0f / fast_sqrt(ss);
    for (int j = 0; j < size; j++) o[j] = weight[j] * (ss * x[j]);
}

// ============================================================================
// SOFTMAX
// ============================================================================
void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) {
        if (x[i] > max_val) max_val = x[i];
    }
    float sum = 0.0f;
    for (int i = 0; i < size; i++) {
        x[i] = fast_exp(x[i] - max_val);
        sum += x[i];
    }
    for (int i = 0; i < size; i++) {
        x[i] /= sum;
    }
}

// ============================================================================
// MATMUL
// ============================================================================
void matmul(float* xout, float* x, float* w, int n, int d) {
    for (int i = 0; i < d; i++) {
        float val = 0.0f;
        for (int j = 0; j < n; j++) {
            val += w[i * n + j] * x[j];
        }
        xout[i] = val;
    }
}

// ============================================================================
// TRANSFORMER FORWARD
// ============================================================================
void transformer(RunState* s, TransformerWeights* w, Config* p, int token, int pos) {
    float* x = s->x;
    int dim = p->dim;
    int hidden_dim = p->hidden_dim;
    int head_size = dim / p->n_heads;

    // Copy token embedding into x
    float* content_row = w->token_embedding_table + token * dim;
    for (int i = 0; i < dim; i++) x[i] = content_row[i];

    // Forward through layers
    for (int l = 0; l < p->n_layers; l++) {
        // Attention
        rmsnorm(s->xb, x, w->rms_att_weight + l * dim, dim);

        matmul(s->q, s->xb, w->wq + l * dim * dim, dim, dim);
        matmul(s->k, s->xb, w->wk + l * dim * dim, dim, dim);
        matmul(s->v, s->xb, w->wv + l * dim * dim, dim, dim);

        // Store in cache
        int loff = l * p->seq_len * dim;
        float* key_cache_row = s->key_cache + loff + pos * dim;
        float* value_cache_row = s->value_cache + loff + pos * dim;
        for (int i = 0; i < dim; i++) {
            key_cache_row[i] = s->k[i];
            value_cache_row[i] = s->v[i];
        }

        // Multihead attention
        for (int h = 0; h < p->n_heads; h++) {
            float* q_head = s->q + h * head_size;
            float* att_head = s->att + h * p->seq_len;

            // Calculate scores
            for (int t = 0; t <= pos; t++) {
                float* k_head = s->key_cache + loff + t * dim + h * head_size;
                float score = 0.0f;
                for (int i = 0; i < head_size; i++) {
                    score += q_head[i] * k_head[i];
                }
                score /= fast_sqrt(head_size);
                att_head[t] = score;
            }

            // Softmax
            softmax(att_head, pos + 1);

            // Weighted sum
            float* xb_head = s->xb + h * head_size;
            for (int i = 0; i < head_size; i++) xb_head[i] = 0.0f;
            for (int t = 0; t <= pos; t++) {
                float* v_head = s->value_cache + loff + t * dim + h * head_size;
                float a = att_head[t];
                for (int i = 0; i < head_size; i++) {
                    xb_head[i] += a * v_head[i];
                }
            }
        }

        // Output projection
        matmul(s->xb2, s->xb, w->wo + l * dim * dim, dim, dim);

        // Residual
        for (int i = 0; i < dim; i++) x[i] += s->xb2[i];

        // FFN
        rmsnorm(s->xb, x, w->rms_ffn_weight + l * dim, dim);
        matmul(s->hb, s->xb, w->w1 + l * dim * hidden_dim, dim, hidden_dim);
        matmul(s->hb2, s->xb, w->w3 + l * dim * hidden_dim, dim, hidden_dim);

        // SiLU
        for (int i = 0; i < hidden_dim; i++) {
            s->hb[i] = s->hb[i] * (1.0f / (1.0f + fast_exp(-s->hb[i])));
        }

        // Elementwise multiply
        for (int i = 0; i < hidden_dim; i++) {
            s->hb[i] = s->hb[i] * s->hb2[i];
        }

        matmul(s->xb, s->hb, w->w2 + l * dim * hidden_dim, hidden_dim, dim);

        // Residual
        for (int i = 0; i < dim; i++) x[i] += s->xb[i];
    }

    // Final
    rmsnorm(x, x, w->rms_final_weight, dim);
    matmul(s->logits, x, w->wcls, dim, p->vocab_size);
}

