    int kv_dim = (config.dim * config.n_kv_heads) / config.n_heads;
    UINT64 state_size = 0;

    state_size += config.dim * sizeof(float);              // x
    state_size += config.dim * sizeof(float);              // xb
    state_size += config.dim * sizeof(float);              // xb2
    state_size += config.hidden_dim * sizeof(float);       // hb
    state_size += config.hidden_dim * sizeof(float);       // hb2
    state_size += config.dim * sizeof(float);              // q
    state_size += config.dim * sizeof(float);              // k
    state_size += config.dim * sizeof(float);              // v
    state_size += config.n_heads * config.seq_len * sizeof(float);  // att
    state_size += config.vocab_size * sizeof(float);       // logits
    state_size += (UINT64)config.n_layers * config.seq_len * kv_dim * sizeof(float);  // key_cache
    state_size += (UINT64)config.n_layers * config.seq_len * kv_dim * sizeof(float);  // value_cache

    Print(L"📏 RunState size: %lu bytes (~%lu MB)\r\n", 
          state_size, state_size / 1048576);

    // Allocate memory for RunState
