    float *state_memory;
    EFI_STATUS Status = uefi_call_wrapper(BS->AllocatePages, 4, AllocateAnyPages, 
                                          EfiLoaderData, NumPages, (EFI_PHYSICAL_ADDRESS*)&state_memory);
    if (EFI_ERROR(Status)) {
        Print(L"❌ State memory allocation failed: %r\r\n", Status);
