    Print(L"   xb2:         0x%lx\r\n", (UINT64)state.xb2);

    state.hb = ptr;
    ptr += config.hidden_dim;
    Print(L"   hb:          0x%lx\r\n", (UINT64)state.hb);

    state.hb2 = ptr;
    ptr += config.hidden_dim;
    Print(L"   hb2:         0x%lx\r\n", (UINT64)state.hb2);

    state.q = ptr;
