// STEP 8: Test minimal forward pass (single layer)
// Tests: RMSNorm, attention (Q/K/V matmul), softmax, output projection

#include <efi.h>
#include <efilib.h>
#include <stdint.h>

// Custom math functions (no libm in UEFI)
float fast_sqrt(float x) {
    if (x <= 0.0f) return 0.0f;
    float xhalf = 0.5f * x;
    int i = *(int*)&x;
    i = 0x5f375a86 - (i >> 1);
    x = *(float*)&i;
    x = x * (1.5f - xhalf * x * x);  // Newton iteration
    x = x * (1.5f - xhalf * x * x);  // Second iteration
    return 1.0f / x;
}

float fast_exp(float x) {
    if (x < -10.0f) return 0.0f;
    if (x > 10.0f) return 22026.0f;
    // Taylor series approximation
    float result = 1.0f + x;
    float term = x;
    for (int i = 2; i < 10; i++) {
        term *= x / i;
        result += term;
    }
    return result;
}

// Hardcoded config for stories15M
#define DIM 288
#define HIDDEN_DIM 768
#define N_LAYERS 6
#define N_HEADS 6
#define N_KV_HEADS 6
#define VOCAB_SIZE 32000
#define SEQ_LEN 256

// Global heap
static UINTN g_heap_base = 0;
static UINTN g_heap_offset = 0;
static UINTN g_heap_size = 0;

void* simple_alloc(UINTN size) {
    if (g_heap_offset + size > g_heap_size) return NULL;
    void* ptr = (void*)(g_heap_base + g_heap_offset);
    g_heap_offset += ((size + 15) & ~15);  // 16-byte align
    return ptr;
}

// Simple RMSNorm
void rmsnorm(float* o, float* x, float* weight, int size) {
    float ss = 0.0f;
    for (int j = 0; j < size; j++) {
        ss += x[j] * x[j];
    }
    ss /= size;
    ss += 1e-5f;
    ss = 1.0f / fast_sqrt(ss);
    for (int j = 0; j < size; j++) {
        o[j] = weight[j] * (ss * x[j]);
    }
}

// Simple matmul: o = x @ w
void matmul(float* o, float* x, float* w, int n, int d) {
    for (int i = 0; i < d; i++) {
        float val = 0.0f;
        for (int j = 0; j < n; j++) {
            val += w[i * n + j] * x[j];
        }
        o[i] = val;
    }
}

// Simple softmax
void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) {
        if (x[i] > max_val) max_val = x[i];
    }
    float sum = 0.0f;
    for (int i = 0; i < size; i++) {
        x[i] = fast_exp(x[i] - max_val);
        sum += x[i];
    }
    for (int i = 0; i < size; i++) {
        x[i] /= sum;
    }
}

