    i = 0x5f375a86 - (i >> 1);
    x = *(float*)&i;
    x = x * (1.5f - xhalf * x * x);
    x = x * (1.5f - xhalf * x * x);
    return 1.0f / x;
}

float fast_exp(float x) {
    if (x < -10.0f) return 0.0f;
    if (x > 10.0f) return 22026.0f;
    float result = 1.0f + x;
    float term = x;
    for (int i = 2; i < 10; i++) {
        term *= x / i;
        result += term;
    }
    return result;
}

// RMSNorm
void rmsnorm(float* o, float* x, float* weight, int size) {
    float ss = 0.0f;
    for (int j = 0; j < size; j++) {
        ss += x[j] * x[j];
    }
    ss /= size;
    ss += 1e-5f;
    ss = 1.0f / fast_sqrt(ss);
    for (int j = 0; j < size; j++) {
        o[j] = weight[j] * (ss * x[j]);
    }
}

// Matmul
void matmul(float* o, float* x, float* w, int n, int d) {
    for (int i = 0; i < d; i++) {
        float val = 0.0f;
        for (int j = 0; j < n; j++) {
            val += w[i * n + j] * x[j];
        }
        o[i] = val;
    }
}

// Softmax
void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) {
        if (x[i] > max_val) max_val = x[i];
    }
    float sum = 0.0f;
    for (int i = 0; i < size; i++) {
        x[i] = fast_exp(x[i] - max_val);
        sum += x[i];
    }
    for (int i = 0; i < size; i++) {
        x[i] /= sum;
    }
}

// Simple transformer layer
void transformer_layer(
    float* x, float* xb, float* q, float* k, float* v, float* att, float* xout,
    float* rms_weight, float* wq, float* wk, float* wv, float* wo
) {
    // RMSNorm
    rmsnorm(xb, x, rms_weight, DIM);

    // Q/K/V
    matmul(q, xb, wq, DIM, DIM);
    matmul(k, xb, wk, DIM, DIM);
    matmul(v, xb, wv, DIM, DIM);

