        att[t] = score / fast_sqrt(DIM);
    }

    // Softmax
    softmax(att, 10);

    // Output
    for (int i = 0; i < DIM; i++) {
        xout[i] = att[0] * v[i];
    }

    // Residual connection
    for (int i = 0; i < DIM; i++) {
        x[i] += xout[i];
    }
}

