    float** wk_weights = (float**)simple_alloc(N_LAYERS * sizeof(float*));
    float** wv_weights = (float**)simple_alloc(N_LAYERS * sizeof(float*));
    float** wo_weights = (float**)simple_alloc(N_LAYERS * sizeof(float*));

    for (int l = 0; l < N_LAYERS; l++) {
        rms_weights[l] = (float*)simple_alloc(DIM * sizeof(float));
        wq_weights[l] = (float*)simple_alloc(DIM * DIM * sizeof(float));
        wk_weights[l] = (float*)simple_alloc(DIM * DIM * sizeof(float));
        wv_weights[l] = (float*)simple_alloc(DIM * DIM * sizeof(float));
        wo_weights[l] = (float*)simple_alloc(DIM * DIM * sizeof(float));
    }

