            } else if (my_strncmp(prompt, "/tui_redraw", 11) == 0) {
                if (!g_gop_fb32) {
                    Print(L"\r\nERROR: GOP not available\r\n\r\n");
                } else {
                    llmk_tui_set_event("/tui_redraw");
