                g_tui_enabled = 1;
                g_tui_dirty = 1;
                llmk_tui_set_event("/tui_mode");
                llmk_tui_redraw_best_effort();
                Print(L"\r\nOK: UI mode=%d\r\n\r\n", g_ui_mode);
