                while (*p == ' ' || *p == '\t') p++;
                int n = 10;
                if (*p) {
                    int v = 0;
                    while (*p >= '0' && *p <= '9') { v = v * 10 + (*p - '0'); p++; }
                    if (v > 0) n = v;
                }
                g_tr_scroll -= n;
                if (g_tr_scroll < 0) g_tr_scroll = 0;
                g_tui_dirty = 1;
                llmk_tui_set_event("/tui_log_down");
                if (g_tui_enabled && g_gop_fb32) llmk_tui_redraw_best_effort();
