                // Usage: /oo_plan <id> [prio] <action...>  (optionally: a1; a2; a3)
                // prio forms: +3, -1, p=2
                int i = 8;
                int id = llmk_parse_entity_id_allow_brackets(prompt, &i);
                while (prompt[i] == ' ') i++;

                int prio = 0;
                // Optional priority token
                if ((prompt[i] == '+' || prompt[i] == '-') && (prompt[i + 1] >= '0' && prompt[i + 1] <= '9')) {
                    int sign = (prompt[i] == '-') ? -1 : 1;
                    i++;
