                } else if (prompt[i] == 'p' && prompt[i + 1] == '=' && (prompt[i + 2] >= '0' && prompt[i + 2] <= '9')) {
                    i += 2;
                    int v = 0;
                    while (prompt[i] >= '0' && prompt[i] <= '9') {
                        v = v * 10 + (prompt[i] - '0');
                        i++;
