                {
                    char dn[196];
                    int dp = 0;
                    const char *h = "done: ";
                    for (int j = 0; h[j] && dp + 1 < (int)sizeof(dn); j++) dn[dp++] = h[j];
                    for (int j = 0; txt[j] && dp + 1 < (int)sizeof(dn); j++) dn[dp++] = txt[j];
                    dn[dp] = 0;
