                while (prompt[i] >= '0' && prompt[i] <= '9') {
                    k = k * 10 + (prompt[i] - '0');
                    i++;
                }
                while (prompt[i] == ' ') i++;
                int sign = 1;
                if (prompt[i] == '-') { sign = -1; i++; }
                else if (prompt[i] == '+') { i++; }
                int pr = 0;
