                    if (djibion_should_block(&g_djibion, &d)) {
                        CHAR16 msg[160];
                        ascii_to_char16(msg, d.reason, (int)(sizeof(msg) / sizeof(msg[0])));
                        Print(L"\r\nDJIBION: blocked (/oo_save): %s\r\n\r\n", msg);
                        continue;
                    }
                    if (d.verdict == DJIBION_VERDICT_TRANSFORM && d.transformed_arg0[0]) {
