                // Best-effort backup (copy previous target -> .bak) before overwriting.
                {
                    CHAR16 bak[120];
                    llmk_make_bak_name(out_name, bak, (int)(sizeof(bak) / sizeof(bak[0])));
                    llmk_copy_file_best_effort(out_name, bak);
