                // Init with deterministic values
                for(int i=0; i<M*K; i++) A[i] = (float)((i % 17) - 8) * 0.1f;
                for(int i=0; i<K*N; i++) B[i] = (float)((i % 19) - 9) * 0.1f;

                // 1. Scalar Baseline
