            } else if (my_strncmp(prompt, "/q8_bench", 9) == 0) {
                // Usage:
                //   /q8_bench           -> default n=d=256, reps=10
                //   /q8_bench <n> <d>   -> custom sizes (n must be multiple of 32)
                //   /q8_bench <n> <d> <reps>
                int n = 256;
                int d = 256;
                int reps = 10;

                int i = 9;
                while (prompt[i] == ' ') i++;
                if (prompt[i] >= '0' && prompt[i] <= '9') {
                    n = 0;
                    while (prompt[i] >= '0' && prompt[i] <= '9') { n = n * 10 + (prompt[i] - '0'); i++; }
