    uefi_call_wrapper(cfh->GetInfo, 4, cfh, &gEfiFileInfoGuid, &cfisz, cfi);
    UINT64 csz = cfi->FileSize;
    uefi_call_wrapper(BS->FreePool, 1, cfi);

