    g_diopion_burst_remaining = (int)turns;
    if (max_tokens > 0) *io_max_gen_tokens = (int)max_tokens;
    if (topk > 0) *io_top_k = (int)topk;
    if (temp_milli > 0) *io_temperature = llmk_temp_from_milli(temp_milli);
