    if (!llmk_json_extract_int_key_range(buf, raw_len, "schema_version", &schema_version)) ok = 0;
    if (!llmk_json_extract_string_key_range(buf, raw_len, "export_kind", export_kind, (int)sizeof(export_kind))) ok = 0;
