/*
 * ADVANCED SIMD MATRIX MULTIPLICATION - ULTIMATE OPTIMIZATIONS
 * 
 * Cutting-edge techniques from BLAS research:
 * 1. Kahan compensated summation (numerical stability)
 * 2. Q8_0 quantized int8 updot with VNNI/maddubs
 * 3. Adaptive cache tiling (L2 awareness)
 * 4. AVX-512 5x5 tile kernels (32 registers)
 * 5. BFloat16 native support (VDPBF16PS)
 * 6. Multiple precision modes (fp32, fp16, bf16, q8_0)
 * 
 * By Djiby Diop - December 2025
 */

#ifndef MATMUL_ADVANCED_H
#define MATMUL_ADVANCED_H

#include <immintrin.h>
#include <stdint.h>

// ============================================================================
// KAHAN COMPENSATED SUMMATION
// ============================================================================

typedef struct {
    float sum;
    float compensation;
} KahanAccumulator;

static inline KahanAccumulator kahan_add(KahanAccumulator acc, float value) {
    float y = value - acc.compensation;
    float t = acc.sum + y;
    acc.compensation = (t - acc.sum) - y;
    acc.sum = t;
    return acc;
}

// Kahan horizontal sum for AVX2 register (8 floats)
static inline float hsum_kahan(__m256 v) {
    KahanAccumulator acc = {0.0f, 0.0f};
    float arr[8];
    _mm256_storeu_ps(arr, v);

    for (int i = 0; i < 8; i++) {
        acc = kahan_add(acc, arr[i]);
    }
    return acc.sum;
}

// ============================================================================
// Q8_0 QUANTIZED INT8 KERNELS WITH UPDOT
// ============================================================================

#if defined(__AVX2__) || defined(__AVX512F__)

// Q8_0 block structure (32 int8 values + 1 fp16 scale)
typedef struct {
    uint16_t d;      // fp16 scale factor
    int8_t qs[32];   // 32 quantized int8 values
} block_q8_0;

// Convert fp16 to fp32
static inline float unhalf(uint16_t h) {
    uint32_t sign = (h & 0x8000) << 16;
    uint32_t exponent = (h & 0x7C00) >> 10;
    uint32_t mantissa = (h & 0x03FF) << 13;

    if (exponent == 0) {
        // Subnormal or zero
        if (mantissa == 0) {
            uint32_t f = sign;
            return *(float*)&f;
        }
        // Normalize subnormal
        while (!(mantissa & 0x00800000)) {
            mantissa <<= 1;
            exponent--;
        }
        mantissa &= ~0x00800000;
        exponent++;
    } else if (exponent == 0x1F) {
        // Inf or NaN
        exponent = 0xFF;
    } else {
        exponent += (127 - 15);
    }

    uint32_t f = sign | (exponent << 23) | mantissa;
    return *(float*)&f;
}

// Updot int8 to float32 with AVX2 VNNI or maddubs
static inline __m256 updot_avx2(__m256i u, __m256i s) {
    __m256i res;

#if defined(__AVXVNNI__) || (defined(__AVX512VNNI__) && defined(__AVX512VL__))
    // VNNI: efficient int8 dot product
    res = _mm256_dpbusd_epi32(_mm256_setzero_si256(), u, s);
#else
    // Fallback: maddubs + madd (2-stage reduction)
    // maddubs: multiply unsigned int8 with signed int8, add pairs -> int16
    __m256i maddubs = _mm256_maddubs_epi16(u, s);
    // madd: multiply int16 pairs and add -> int32
    res = _mm256_madd_epi16(_mm256_set1_epi16(1), maddubs);
#endif

    // Convert int32 to float32
    return _mm256_cvtepi32_ps(res);
}

// Q8_0 3x3 tile kernel (optimized for quantized matmul)
static void llmm3x3_q8_avx2(int m0, int m, int n0, int n, int k,
                             const block_q8_0* A, int lda,
                             const block_q8_0* B, int ldb,
                             float* C, int ldc) {
    for (int i = m0; i < m && i + 2 < m; i += 3) {
        for (int j = n0; j < n && j + 2 < n; j += 3) {
            // 9 accumulators for 3x3 tile
            __m256 c00 = _mm256_setzero_ps();
            __m256 c01 = _mm256_setzero_ps();
            __m256 c02 = _mm256_setzero_ps();
            __m256 c10 = _mm256_setzero_ps();
            __m256 c11 = _mm256_setzero_ps();
            __m256 c12 = _mm256_setzero_ps();
            __m256 c20 = _mm256_setzero_ps();
            __m256 c21 = _mm256_setzero_ps();
            __m256 c22 = _mm256_setzero_ps();

            // Each Q8_0 block has 32 int8 values
            for (int l = 0; l < k; l++) {
                // Load int8 vectors (32 values = 256 bits)
                __m256i a0_q = _mm256_loadu_si256((const __m256i*)A[lda * (i + 0) + l].qs);
                __m256i a1_q = _mm256_loadu_si256((const __m256i*)A[lda * (i + 1) + l].qs);
                __m256i a2_q = _mm256_loadu_si256((const __m256i*)A[lda * (i + 2) + l].qs);

                __m256i b0_q = _mm256_loadu_si256((const __m256i*)B[ldb * (j + 0) + l].qs);
                __m256i b1_q = _mm256_loadu_si256((const __m256i*)B[ldb * (j + 1) + l].qs);
                __m256i b2_q = _mm256_loadu_si256((const __m256i*)B[ldb * (j + 2) + l].qs);

                // Compute scale factors (fp16 -> fp32)
                float d00 = unhalf(A[lda * (i + 0) + l].d) * unhalf(B[ldb * (j + 0) + l].d);
                float d01 = unhalf(A[lda * (i + 0) + l].d) * unhalf(B[ldb * (j + 1) + l].d);
                float d02 = unhalf(A[lda * (i + 0) + l].d) * unhalf(B[ldb * (j + 2) + l].d);
                float d10 = unhalf(A[lda * (i + 1) + l].d) * unhalf(B[ldb * (j + 0) + l].d);
                float d11 = unhalf(A[lda * (i + 1) + l].d) * unhalf(B[ldb * (j + 1) + l].d);
                float d12 = unhalf(A[lda * (i + 1) + l].d) * unhalf(B[ldb * (j + 2) + l].d);
                float d20 = unhalf(A[lda * (i + 2) + l].d) * unhalf(B[ldb * (j + 0) + l].d);
                float d21 = unhalf(A[lda * (i + 2) + l].d) * unhalf(B[ldb * (j + 1) + l].d);
                float d22 = unhalf(A[lda * (i + 2) + l].d) * unhalf(B[ldb * (j + 2) + l].d);

                // Updot and accumulate with scale
                c00 = _mm256_fmadd_ps(_mm256_set1_ps(d00), updot_avx2(a0_q, b0_q), c00);
                c01 = _mm256_fmadd_ps(_mm256_set1_ps(d01), updot_avx2(a0_q, b1_q), c01);
                c02 = _mm256_fmadd_ps(_mm256_set1_ps(d02), updot_avx2(a0_q, b2_q), c02);
                c10 = _mm256_fmadd_ps(_mm256_set1_ps(d10), updot_avx2(a1_q, b0_q), c10);
                c11 = _mm256_fmadd_ps(_mm256_set1_ps(d11), updot_avx2(a1_q, b1_q), c11);
                c12 = _mm256_fmadd_ps(_mm256_set1_ps(d12), updot_avx2(a1_q, b2_q), c12);
                c20 = _mm256_fmadd_ps(_mm256_set1_ps(d20), updot_avx2(a2_q, b0_q), c20);
                c21 = _mm256_fmadd_ps(_mm256_set1_ps(d21), updot_avx2(a2_q, b1_q), c21);
                c22 = _mm256_fmadd_ps(_mm256_set1_ps(d22), updot_avx2(a2_q, b2_q), c22);
            }

            // Horizontal sum with Kahan compensation for better precision
            C[ldc * (j + 0) + (i + 0)] = hsum_kahan(c00);
            C[ldc * (j + 1) + (i + 0)] = hsum_kahan(c01);
            C[ldc * (j + 2) + (i + 0)] = hsum_kahan(c02);
            C[ldc * (j + 0) + (i + 1)] = hsum_kahan(c10);
            C[ldc * (j + 1) + (i + 1)] = hsum_kahan(c11);
            C[ldc * (j + 2) + (i + 1)] = hsum_kahan(c12);
            C[ldc * (j + 0) + (i + 2)] = hsum_kahan(c20);
            C[ldc * (j + 1) + (i + 2)] = hsum_kahan(c21);
            C[ldc * (j + 2) + (i + 2)] = hsum_kahan(c22);
        }
    }
}

