            // 25 accumulators (5x5 tile) - leverages AVX-512's 32 registers
            __m512 c00 = _mm512_setzero_ps();
            __m512 c01 = _mm512_setzero_ps();
            __m512 c02 = _mm512_setzero_ps();
            __m512 c03 = _mm512_setzero_ps();
            __m512 c04 = _mm512_setzero_ps();
