// ============================================================================
// ADAPTIVE CACHE TILING
// ============================================================================

// Get L2 cache size via CPUID
static inline int get_l2_cache_size() {
    uint32_t eax, ebx, ecx, edx;

    // CPUID leaf 0x80000006: L2 cache info
    __asm__ volatile(
        "cpuid"
        : "=a"(eax), "=b"(ebx), "=c"(ecx), "=d"(edx)
        : "a"(0x80000006), "c"(0)
    );

    // ECX bits 16-31: L2 cache size in KB
    int l2_kb = (ecx >> 16) & 0xFFFF;
    return l2_kb * 1024;  // Return in bytes
}

// Adaptive blocked matmul - adjusts tile size to fit L2 cache
static void matmul_adaptive_cache(int m, int n, int k,
                                   const float* A, int lda,
                                   const float* B, int ldb,
                                   float* C, int ldc,
                                   void (*kernel_func)(int, int, int, int, int,
                                                      const float*, int,
                                                      const float*, int,
                                                      float*, int)) {
    // Get L2 cache size (typically 256KB-512KB)
    int l2_size = get_l2_cache_size();
    if (l2_size == 0) l2_size = 256 * 1024;  // Default: 256KB

    // Calculate optimal tile size
    // We want: tile_m * tile_k + tile_k * tile_n + tile_m * tile_n < L2_size
    // Simplified: tile_size^2 * 3 * sizeof(float) < L2_size
    int tile_elements = l2_size / (3 * sizeof(float));
    int tile_size = 64;  // Start with 64

    // Find largest power-of-2 tile that fits
    while (tile_size * tile_size * 3 > tile_elements && tile_size > 16) {
        tile_size /= 2;
    }

    // Tile the computation
    for (int ii = 0; ii < m; ii += tile_size) {
        for (int jj = 0; jj < n; jj += tile_size) {
            for (int kk = 0; kk < k; kk += tile_size) {
                int tile_m = (ii + tile_size > m) ? m - ii : tile_size;
                int tile_n = (jj + tile_size > n) ? n - jj : tile_size;
                int tile_k = (kk + tile_size > k) ? k - kk : tile_size;

                // Call optimized kernel on tile
                kernel_func(ii, ii + tile_m, jj, jj + tile_n, tile_k,
                           A + ii * lda + kk, lda,
                           B + kk * ldb + jj, ldb,
                           C + ii * ldc + jj, ldc);
            }
        }
    }
}

#endif // MATMUL_ADVANCED_H
