#include <efilib.h>

// ============================================================================
// CPU FEATURE DETECTION
// ============================================================================

typedef struct {
    BOOLEAN has_sse2;
    BOOLEAN has_avx;
    BOOLEAN has_avx2;
    BOOLEAN has_avx512;
