// Release manual hold and reset consecutive counters (REPL /dplus_reset).
static void oo_dplus_gate_reset(DPlusGateCtx *g) {
    if (!g) return;
    g->verdict          = OO_DPLUS_ALLOW;
    g->consec_non_allow = 0;
    g->consec_emergency = 0;
