// soma_cortex.h — SomaMind Phase J: oo-model Cortex Loader
//
// Loads a compact OOSS model (15M–130M params from oo-model) as a fast
// "cortex" brain. Runs before Mamba-2.8B to provide:
//   1. Domain classification (routes to right temperature/top_p)
//   2. Safety pre-check (flags policy-sensitive prompts)
//   3. Response prefix generation (short seed for the big model)
//
// The cortex runs in O(1) memory (SSM recurrent state) and is designed
// to be < 5ms on bare metal x86 for the compact models.
//
// Weights live in LLMK_ARENA_ZONE_C (dedicated cold arena).
// Runtime buffers come from LLMK_ARENA_SCRATCH (shared scratch).
//
// Freestanding C11 — no libc, no malloc.

#pragma once

