#include "../ssm/oosi_v3_infer.h"

#ifdef __cplusplus
extern "C" {
#endif

// ============================================================
// Configuration
// ============================================================
#define SOMA_CORTEX_MAX_TOKENS    16    // Max tokens cortex generates (fast path)
#define SOMA_CORTEX_PREFIX_LEN    128   // Max ASCII prefix cortex produces
#define SOMA_CORTEX_MODEL_LEN     48    // Max cortex model filename length

// Safety score thresholds (0-100)
#define SOMA_CORTEX_SAFE_THRESHOLD  30  // Below = flag as policy concern
#define SOMA_CORTEX_SAFE_DEFAULT    70  // Default when cortex not loaded

// ============================================================
// Cortex result
// ============================================================
typedef struct {
    int         valid;           // 1 = cortex ran successfully
    int         n_tokens;        // Tokens generated by cortex

    // Domain classification (mirrors SomaDomain from soma_router.h)
    int         domain;          // 0-6, SOMA_DOMAIN_*
    int         domain_conf;     // 0-100 confidence

    // Safety check (policy / D+ gate)
    int         safety_score;    // 0=unsafe 100=safe (from logit distribution)
    int         safety_flagged;  // 1 = below threshold (blocks or warns)

    // Response prefix (optional short seed for big model)
    char        prefix[SOMA_CORTEX_PREFIX_LEN];
    int         prefix_len;

    // Raw token IDs from cortex generation
    int         token_ids[SOMA_CORTEX_MAX_TOKENS];
} SomaCortexResult;

// ============================================================
// Context
// ============================================================
typedef struct {
    int          loaded;          // 1 = weights and ctx are ready
    int          enabled;         // 1 = used in inference pipeline
    int          total_calls;     // Inference calls since load
    int          total_flagged;   // Prompts flagged by safety check
    char         model_name[SOMA_CORTEX_MODEL_LEN];

    OosiV3Weights  weights;       // Parsed weight pointers (into buf)
    OosiV3GenCtx   ctx;           // Inference state

