// ============================================================
// API
// ============================================================

// Initialize context (zero it out, set enabled=0).
void soma_cortex_init(SomaCortexCtx *ctx);

// Load a small OOSS model for use as cortex.
// buf must stay alive (arena-backed in god file).
// Allocates runtime buffers from zones (SCRATCH + ZONE_C used for weights alloc).
// Returns 0 on success, -1 on failure.
int soma_cortex_load(SomaCortexCtx *ctx,
                     const void *buf, unsigned long long len,
                     const char *model_name);

// Run cortex inference on a prompt (ASCII, NUL-terminated).
// Returns a filled SomaCortexResult. If ctx not loaded, returns result.valid=0.
SomaCortexResult soma_cortex_run(SomaCortexCtx *ctx, const char *prompt);

// Print cortex stats (for /cortex_stats REPL command).
