// SSM inference engine — freestanding bare-metal Mamba inference
// Single-token recurrent mode: O(1) memory, no KV cache needed.
// Compatible with UEFI (-ffreestanding, -mno-red-zone, no libc)

#include "ssm_types.h"
#include "mamba_block.h"

