// TinyBLAS - Fast matmul kernels (portable, no dependencies)
// Optimized for UEFI bare-metal

#ifndef TINYBLAS_H
#define TINYBLAS_H

#include <efi.h>
#include <efilib.h>

// SSE2/AVX2 detection
static int has_avx2 = 0;

static inline void cpuid(int leaf, int *eax, int *ebx, int *ecx, int *edx) {
    __asm__ __volatile__(
        "cpuid"
        : "=a"(*eax), "=b"(*ebx), "=c"(*ecx), "=d"(*edx)
        : "a"(leaf)
    );
}

static void detect_cpu_features(void) {
    int eax, ebx, ecx, edx;
    cpuid(1, &eax, &ebx, &ecx, &edx);
    // AVX2 requires AVX (ecx bit 28) + AVX2 (leaf 7 ebx bit 5)
    if (ecx & (1 << 28)) {
        cpuid(7, &eax, &ebx, &ecx, &edx);
        has_avx2 = (ebx & (1 << 5)) != 0;
    }
}

// Horizontal sum for __m256
static inline float hsum_avx(__m256 v) {
    __m128 lo = _mm256_castps256_ps128(v);
    __m128 hi = _mm256_extractf128_ps(v, 1);
    lo = _mm_add_ps(lo, hi);
    __m128 shuf = _mm_movehdup_ps(lo);
    lo = _mm_add_ps(lo, shuf);
    shuf = _mm_movehl_ps(shuf, lo);
    lo = _mm_add_ss(lo, shuf);
    return _mm_cvtss_f32(lo);
}

// Horizontal sum for __m128
static inline float hsum_sse(__m128 v) {
    __m128 shuf = _mm_movehdup_ps(v);
    v = _mm_add_ps(v, shuf);
    shuf = _mm_movehl_ps(shuf, v);
    v = _mm_add_ss(v, shuf);
    return _mm_cvtss_f32(v);
}

// 1x4 kernel (AVX2) - unroll outer loop
static void matmul_1x4_avx2(float* C, const float* A, const float* B,
                             int i, int j, int k, int lda, int ldb, int ldc) {
    __m256 c0 = _mm256_setzero_ps();
    __m256 c1 = _mm256_setzero_ps();
    __m256 c2 = _mm256_setzero_ps();
    __m256 c3 = _mm256_setzero_ps();

    for (int l = 0; l < k; l += 8) {
        __m256 a0 = _mm256_loadu_ps(A + lda * i + l);
        __m256 b0 = _mm256_loadu_ps(B + ldb * (j + 0) + l);
        __m256 b1 = _mm256_loadu_ps(B + ldb * (j + 1) + l);
        __m256 b2 = _mm256_loadu_ps(B + ldb * (j + 2) + l);
        __m256 b3 = _mm256_loadu_ps(B + ldb * (j + 3) + l);
        c0 = _mm256_fmadd_ps(a0, b0, c0);
        c1 = _mm256_fmadd_ps(a0, b1, c1);
        c2 = _mm256_fmadd_ps(a0, b2, c2);
        c3 = _mm256_fmadd_ps(a0, b3, c3);
    }

    C[ldc * (j + 0) + i] = hsum_avx(c0);
    C[ldc * (j + 1) + i] = hsum_avx(c1);
    C[ldc * (j + 2) + i] = hsum_avx(c2);
    C[ldc * (j + 3) + i] = hsum_avx(c3);
}

// 1x1 kernel (SSE2 fallback)
static void matmul_1x1_sse2(float* C, const float* A, const float* B,
                             int i, int j, int k, int lda, int ldb, int ldc) {
    __m128 c = _mm_setzero_ps();

    for (int l = 0; l < k; l += 4) {
        __m128 a = _mm_loadu_ps(A + lda * i + l);
        __m128 b = _mm_loadu_ps(B + ldb * j + l);
        c = _mm_add_ps(c, _mm_mul_ps(a, b));
    }

    C[ldc * j + i] = hsum_sse(c);
}

// Fast matmul (tinyBLAS-style kernels)
void matmul_fast(float* C, const float* A, const float* B,
                 int m, int n, int k) {
    int lda = k;
    int ldb = k;
    int ldc = m;

    if (has_avx2) {
        // AVX2 path: tile 1x4
        int j = 0;
        for (; j + 3 < n; j += 4) {
            for (int i = 0; i < m; i++) {
                matmul_1x4_avx2(C, A, B, i, j, k, lda, ldb, ldc);
            }
        }
        // Remainder
        for (; j < n; j++) {
            for (int i = 0; i < m; i++) {
                matmul_1x1_sse2(C, A, B, i, j, k, lda, ldb, ldc);
            }
        }
    } else {
        // SSE2 fallback
        for (int j = 0; j < n; j++) {
            for (int i = 0; i < m; i++) {
                matmul_1x1_sse2(C, A, B, i, j, k, lda, ldb, ldc);
            }
        }
    }
}

#endif // TINYBLAS_H
