// Encode UTF-16 string at compile time
macro_rules! ucs2 {
    ($s:expr) => {{
        const S: &str = $s;
        const LEN: usize = S.len() + 1;
        const fn encode(s: &str) -> [u16; LEN] {
            let bytes = s.as_bytes();
            let mut out = [0u16; LEN];
            let mut i = 0;
            while i < bytes.len() {
                out[i] = bytes[i] as u16;
                i += 1;
            }
            out
        }
        encode(S)
    }};
}

#[no_mangle]
