// zig build-exe entry.zig -target x86_64-uefi -O ReleaseFast

const std = @import("std");
const uefi = std.os.uefi;

pub fn main() callconv(.C) uefi.Status {
    const con_out = uefi.system_table.con_out orelse return .Aborted;

    _ = con_out.reset(false);

    const banner = "Djibion UEFI — Zig Runtime
";
    _ = con_out.outputString(std.unicode.utf8ToUtf16LeStringLiteral(banner));

    // CPUID feature detection
    const leaf1 = cpuid(1);
    const has_sse2  = (leaf1.edx >> 26) & 1 == 1;
    const has_avx   = (leaf1.ecx >> 28) & 1 == 1;
    const has_avx2  = blk: {
        const leaf7 = cpuid(7);
        break :blk (leaf7.ebx >> 5) & 1 == 1 and has_avx;
    };

    const feat_msg = if (has_avx2)
        "CPU: AVX2 + FMA ready
"
    else if (has_avx)
        "CPU: AVX ready
"
    else if (has_sse2)
        "CPU: SSE2 baseline
"
    else
        "CPU: Scalar fallback
";

    _ = con_out.outputString(std.unicode.utf8ToUtf16LeStringLiteral(feat_msg));

    // Comptime-selected matrix kernel
    const kernel = comptime selectKernel();
    _ = kernel; // wire into inference pipeline

    // Spin — replace with model load + REPL
    while (true) {
        asm volatile ("pause" ::: "memory");
    }
}

fn cpuid(leaf: u32) struct { eax: u32, ebx: u32, ecx: u32, edx: u32 } {
    var eax: u32 = leaf;
    var ebx: u32 = 0;
    var ecx: u32 = 0;
    var edx: u32 = 0;
    asm ("cpuid"
        : [_eax] "={eax}" (eax),
          [_ebx] "={ebx}" (ebx),
          [_ecx] "={ecx}" (ecx),
          [_edx] "={edx}" (edx)
        : [leaf] "{eax}" (leaf)
        : "memory"
    );
    return .{ .eax = eax, .ebx = ebx, .ecx = ecx, .edx = edx };
}

fn selectKernel() type {
    // Zig comptime: choose kernel at compile time based on target features
    if (@import("builtin").cpu.features.isEnabled(.avx2)) {
        return @import("kernels/avx2.zig");
    } else {
        return @import("kernels/scalar.zig");
    }
}
