```asm
/* boot.S — ARM64 bare-metal bootloader
 * Target: aarch64-none-elf
 * Linked at 0x40000000 (QEMU virt machine DRAM base)
 * Assemble: aarch64-linux-gnu-gcc -nostdlib -T link.ld boot.S -o kernel.elf
 */

.section ".text.boot"
.global _start

_start:
    /* ── Core 0 only ──────────────────────────────── */
    mrs     x0, mpidr_el1       // read CPU affinity
    and     x0, x0, #0xFF       // mask core ID
    cbnz    x0, .park           // park all cores except core 0

    /* ── Set stack pointer ────────────────────────── */
    // Stack grows downward from _start (loaded at 0x40000000)
    ldr     x30, =_start
    mov     sp, x30

    /* ── Zero BSS ─────────────────────────────────── */
    ldr     x1, =__bss_start
    ldr     x2, =__bss_end
.zero_bss:
    cmp     x1, x2
    b.ge    .bss_done
    str     xzr, [x1], #8      // zero 8 bytes, advance pointer
    b       .zero_bss
.bss_done:

    /* ── Copy .data from ROM to RAM (if flash target) */
    // (omitted for QEMU — already in RAM)

    /* ── Configure SCTLR_EL1: I-cache, disable MMU ── */
    mrs     x0, sctlr_el1
    orr     x0, x0, #(1 << 12)  // enable I-cache
    bic     x0, x0, #1          // disable MMU (safe start)
    msr     sctlr_el1, x0
    isb

    /* ── Branch to C kernel ──────────────────────── */
    bl      kernel_main

    /* ── Should never return — halt ─────────────── */
.halt:
    wfe
    b       .halt

.park:
    wfe
    b       .park

/* ── Exception vector table (minimal, 16-byte aligned) */
.section ".text.vectors"
.align 11
.global vectors
vectors:
    .rept 16
    b .halt         // stub all 16 exception entries
    .space 0x80 - 4
    .endr
