// D+ source file: example.dp

module soma::cortex;

// Ownership like Rust, syntax more like C
fn add_tensors(owned a: Tensor[f32, 512], ref b: Tensor[f32, 512]) -> Tensor[f32, 512] {
    return a + b;   // operator overloaded, SIMD-dispatched
}

// Comptime generics (resolved at compile time, zero overhead)
comptime fn gemm<T: Float, M: uint, N: uint, K: uint>(
    a: Tensor[T, M, K],
    b: Tensor[T, K, N],
