```c
/* djibcc_lexer.c — D+ Compiler Bootstrap Lexer
 * Written in C for maximum portability (bare metal + hosted)
 * Djiby Diop, 2025
 */

#include <stdint.h>
#include <stdbool.h>
#include <string.h>

typedef enum {
    // Literals
    DP_TOK_INT, DP_TOK_FLOAT, DP_TOK_STRING, DP_TOK_IDENT,
    // Keywords
    DP_TOK_FN, DP_TOK_LET, DP_TOK_OWNED, DP_TOK_REF,
    DP_TOK_COMPTIME, DP_TOK_MMIO, DP_TOK_MODULE, DP_TOK_UNSAFE,
    DP_TOK_TENSOR, DP_TOK_RETURN, DP_TOK_IF, DP_TOK_ELSE,
    DP_TOK_FOR, DP_TOK_WHILE, DP_TOK_MACRO,
    // Types
    DP_TOK_U8, DP_TOK_U16, DP_TOK_U32, DP_TOK_U64,
    DP_TOK_I32, DP_TOK_I64, DP_TOK_F32, DP_TOK_F64, DP_TOK_BF16,
    // Operators
    DP_TOK_PLUS, DP_TOK_MINUS, DP_TOK_STAR, DP_TOK_SLASH,
    DP_TOK_AT,          // @ for intrinsics
    DP_TOK_ARROW,       // ->
    DP_TOK_FAT_ARROW,   // =>
    DP_TOK_EQ, DP_TOK_EQEQ, DP_TOK_NEQ, DP_TOK_LT, DP_TOK_GT,
    DP_TOK_COLON, DP_TOK_SEMI, DP_TOK_COMMA, DP_TOK_DOT,
    DP_TOK_LBRACE, DP_TOK_RBRACE, DP_TOK_LPAREN, DP_TOK_RPAREN,
    DP_TOK_LBRACKET, DP_TOK_RBRACKET,
    DP_TOK_EOF, DP_TOK_ERROR
} DPTokenKind;

typedef struct {
    DPTokenKind kind;
    const char *start;
    uint32_t    len;
    uint32_t    line;
} DPToken;

typedef struct {
    const char *src;
    uint32_t    pos;
    uint32_t    line;
} DPLexer;

static const struct { const char *kw; DPTokenKind tok; } KEYWORDS[] = {
    {"fn",       DP_TOK_FN},
    {"let",      DP_TOK_LET},
    {"owned",    DP_TOK_OWNED},
    {"ref",      DP_TOK_REF},
    {"comptime", DP_TOK_COMPTIME},
    {"mmio",     DP_TOK_MMIO},
    {"module",   DP_TOK_MODULE},
    {"unsafe",   DP_TOK_UNSAFE},
    {"tensor",   DP_TOK_TENSOR},
    {"return",   DP_TOK_RETURN},
    {"if",       DP_TOK_IF},
    {"else",     DP_TOK_ELSE},
    {"for",      DP_TOK_FOR},
    {"while",    DP_TOK_WHILE},
    {"macro",    DP_TOK_MACRO},
    {"f32",      DP_TOK_F32},
    {"f64",      DP_TOK_F64},
    {"u32",      DP_TOK_U32},
    {"u64",      DP_TOK_U64},
    {"i32",      DP_TOK_I32},
    {"i64",      DP_TOK_I64},
    {"bf16",     DP_TOK_BF16},
};
#define KEYWORDS_N (sizeof(KEYWORDS)/sizeof(KEYWORDS[0]))

static inline char peek_c(DPLexer *l) { return l->src[l->pos]; }
static inline char adv(DPLexer *l)    { return l->src[l->pos++]; }

static DPTokenKind ident_or_keyword(const char *s, uint32_t len) {
    for (uint32_t i = 0; i < KEYWORDS_N; i++) {
        if (strlen(KEYWORDS[i].kw) == len &&
            memcmp(KEYWORDS[i].kw, s, len) == 0)
            return KEYWORDS[i].tok;
    }
    return DP_TOK_IDENT;
}

DPToken dp_next_token(DPLexer *l) {
    // Skip whitespace and comments
    for (;;) {
        while (peek_c(l) == ' ' || peek_c(l) == '\t' || peek_c(l) == '\r') l->pos++;
        if (peek_c(l) == '\n') { l->pos++; l->line++; continue; }
        if (peek_c(l) == '/' && l->src[l->pos+1] == '/') {
            while (peek_c(l) && peek_c(l) != '\n') l->pos++;
            continue;
        }
        break;
    }

    uint32_t start_pos  = l->pos;
    uint32_t start_line = l->line;
    char c = adv(l);

    if (c == '\0') return (DPToken){DP_TOK_EOF, l->src+start_pos, 0, start_line};

    // Identifiers and keywords
    if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || c == '_') {
        while (peek_c(l) && (
            (peek_c(l) >= 'a' && peek_c(l) <= 'z') ||
            (peek_c(l) >= 'A' && peek_c(l) <= 'Z') ||
            (peek_c(l) >= '0' && peek_c(l) <= '9') ||
            peek_c(l) == '_')) l->pos++;
        uint32_t len = l->pos - start_pos;
        DPTokenKind kind = ident_or_keyword(l->src + start_pos, len);
        return (DPToken){kind, l->src + start_pos, len, start_line};
    }

    // Integer / float literals
    if (c >= '0' && c <= '9') {
        bool is_float = false;
        while (peek_c(l) >= '0' && peek_c(l) <= '9') l->pos++;
        if (peek_c(l) == '.') { is_float = true; l->pos++;
            while (peek_c(l) >= '0' && peek_c(l) <= '9') l->pos++; }
        return (DPToken){is_float ? DP_TOK_FLOAT : DP_TOK_INT,
                         l->src + start_pos, l->pos - start_pos, start_line};
    }

    // Operators and punctuation
    switch (c) {
        case '+': return (DPToken){DP_TOK_PLUS,     l->src+start_pos, 1, start_line};
        case '-': if (peek_c(l) == '>') { l->pos++; return (DPToken){DP_TOK_ARROW, l->src+start_pos, 2, start_line}; }
                  return (DPToken){DP_TOK_MINUS,    l->src+start_pos, 1, start_line};
        case '*': return (DPToken){DP_TOK_STAR,     l->src+start_pos, 1, start_line};
        case '@': return (DPToken){DP_TOK_AT,       l->src+start_pos, 1, start_line};
        case '=': if (peek_c(l)=='='){l->pos++; return (DPToken){DP_TOK_EQEQ, l->src+start_pos,2,start_line};}
                  return (DPToken){DP_TOK_EQ,       l->src+start_pos, 1, start_line};
        case ':': return (DPToken){DP_TOK_COLON,    l->src+start_pos, 1, start_line};
        case ';': return (DPToken){DP_TOK_SEMI,     l->src+start_pos, 1, start_line};
        case ',': return (DPToken){DP_TOK_COMMA,    l->src+start_pos, 1, start_line};
        case '{': return (DPToken){DP_TOK_LBRACE,   l->src+start_pos, 1, start_line};
        case '}': return (DPToken){DP_TOK_RBRACE,   l->src+start_pos, 1, start_line};
        case '(': return (DPToken){DP_TOK_LPAREN,   l->src+start_pos, 1, start_line};
        case ')': return (DPToken){DP_TOK_RPAREN,   l->src+start_pos, 1, start_line};
        case '[': return (DPToken){DP_TOK_LBRACKET, l->src+start_pos, 1, start_line};
        case ']': return (DPToken){DP_TOK_RBRACKET, l->src+start_pos, 1, start_line};
        default:  return (DPToken){DP_TOK_ERROR,    l->src+start_pos, 1, start_line};
    }
}
```
