Forth is the original bare-metal language — it ran on early microcomputers with 4KB RAM. Its virtues for firmware:
- Zero dependencies: the entire interpreter is ~2KB of C
- Extensible: define new words (functions) interactively over serial
- Direct memory access: natural, not bolted on
- Stack-based: no register allocation, trivial to compile

```c
/* djib_forth.c — Minimal Forth interpreter for UEFI/bare metal
 * Runs without malloc, libc, or OS
 * Stack machine with 64 built-in words
 */

#define STACK_SIZE  256
#define DICT_SIZE   512
#define MEM_SIZE    (64*1024)

typedef long cell;  // native word size

static cell   data_stack[STACK_SIZE];
static int    dsp = 0;  // data stack pointer

static cell   ret_stack[STACK_SIZE];
static int    rsp = 0;  // return stack pointer

static char   memory[MEM_SIZE];
static int    here = 0;  // next free memory address

// Stack operations
#define PUSH(v)  (data_stack[dsp++] = (v))
#define POP()    (data_stack[--dsp])
#define TOS      (data_stack[dsp-1])

// Dictionary entry
typedef struct Word {
    char name[32];
    void (*primitive)(void);
    struct Word *next;
} Word;

static Word dict[DICT_SIZE];
static int  dict_n = 0;
static Word *latest = NULL;

static void define(const char *name, void (*fn)(void)) {
    Word *w = &dict[dict_n++];
    __builtin_strncpy(w->name, name, 31);
    w->primitive = fn;
    w->next = latest;
    latest = w;
}

// Built-in primitives
static void w_dup(void)  { cell a = TOS; PUSH(a); }
static void w_drop(void) { dsp--; }
static void w_swap(void) { cell a=POP(), b=POP(); PUSH(a); PUSH(b); }
static void w_add(void)  { cell b=POP(); TOS += b; }
static void w_sub(void)  { cell b=POP(); TOS -= b; }
static void w_mul(void)  { cell b=POP(); TOS *= b; }
static void w_store(void){ cell addr=POP(), val=POP(); *(cell*)(uintptr_t)addr = val; }
static void w_fetch(void){ cell addr=POP(); PUSH(*(cell*)(uintptr_t)addr); }
static void w_emit(void) { char c=(char)POP(); uart_putc(c); }  // bare metal output
static void w_dot(void)  { print_int(POP()); }

void forth_init(void) {
    define("dup",  w_dup);
    define("drop", w_drop);
    define("swap", w_swap);
    define("+",    w_add);
    define("-",    w_sub);
    define("*",    w_mul);
    define("!",    w_store);
    define("@",    w_fetch);
    define("emit", w_emit);
    define(".",    w_dot);
}

Word *find_word(const char *name) {
    for (Word *w = latest; w; w = w->next)
        if (__builtin_strcmp(w->name, name) == 0) return w;
    return NULL;
}

void forth_eval(const char *line) {
    // Simple tokenizer: space-delimited words
    char tok[64];
    int i = 0;
    while (*line) {
        if (*line == ' ' || *line == '\n' || *line == '\0') {
            if (i > 0) {
                tok[i] = '\0'; i = 0;
                Word *w = find_word(tok);
                if (w) {
                    w->primitive();
                } else {
                    // Try as integer literal
                    char *end;
                    cell v = simple_strtol(tok, &end, 10);
                    if (end != tok) PUSH(v);
                }
            }
        } else {
            tok[i++] = *line;
        }
        if (*line) line++;
    }
}
```

