    size_t              dma_size;

    struct completion   irq_done;   // synchronize with interrupt
    spinlock_t          lock;
};

static struct class *djibion_class;
static int major;

/* ── Interrupt handler ─────────────────────────── */
static irqreturn_t djibion_irq(int irq, void *data) {
    struct djibion_dev *dev = data;
    u32 status = ioread32(dev->regs + REG_STATUS);

    if (!(status & STATUS_READY)) return IRQ_NONE;

    // Acknowledge interrupt
    iowrite32(0, dev->regs + REG_STATUS);

    // Wake up any waiting process
    complete(&dev->irq_done);
    return IRQ_HANDLED;
}

/* ── File operations ───────────────────────────── */
static long djibion_ioctl(struct file *f, unsigned int cmd, unsigned long arg) {
    struct djibion_dev *dev = f->private_data;

    switch (cmd) {
    case 0x44420001: {  // DJIB_INFER
        u32 token_count;
        if (copy_from_user(&token_count, (void __user *)arg, sizeof(u32)))
            return -EFAULT;

        // Program DMA
        iowrite64(dev->dma_handle, dev->regs + REG_DMA_ADDR);
        iowrite32(token_count * sizeof(float), dev->regs + REG_DMA_LEN);

        // Start inference
        reinit_completion(&dev->irq_done);
        iowrite32(CTL_START | CTL_IRQ_EN, dev->regs + REG_CONTROL);

        // Wait for completion (100ms timeout)
        if (!wait_for_completion_timeout(&dev->irq_done, HZ/10))
            return -ETIMEDOUT;

        return ioread32(dev->regs + REG_RESULT);
    }
    default:
        return -ENOTTY;
    }
}

static int djibion_mmap(struct file *f, struct vm_area_struct *vma) {
    struct djibion_dev *dev = f->private_data;
    // Map DMA buffer to userspace for zero-copy I/O
    return dma_mmap_coherent(&dev->pdev->dev, vma,
                             dev->dma_buf, dev->dma_handle,
                             vma->vm_end - vma->vm_start);
}

static const struct file_operations djibion_fops = {
    .owner          = THIS_MODULE,
    .unlocked_ioctl = djibion_ioctl,
    .mmap           = djibion_mmap,
};

/* ── PCI probe ─────────────────────────────────── */
static int djibion_probe(struct pci_dev *pdev, const struct pci_device_id *id) {
    struct djibion_dev *dev;
    int err;

    dev = devm_kzalloc(&pdev->dev, sizeof(*dev), GFP_KERNEL);
    if (!dev) return -ENOMEM;

    pci_set_drvdata(pdev, dev);
    dev->pdev = pdev;

    err = pcim_enable_device(pdev);
    if (err) return err;

    pci_set_master(pdev);  // enable bus mastering (DMA)

    err = pcim_iomap_regions(pdev, BIT(DJIBION_BAR), "djibion");
    if (err) return err;
    dev->regs = pcim_iomap_table(pdev)[DJIBION_BAR];

    // Setup 64-bit DMA
    err = dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(64));
    if (err) { err = dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(32)); }
    if (err) return err;

    dev->dma_size = 64 * 1024 * 1024;  // 64MB inference buffer
    dev->dma_buf  = dma_alloc_coherent(&pdev->dev, dev->dma_size,
                                       &dev->dma_handle, GFP_KERNEL);
    if (!dev->dma_buf) return -ENOMEM;

    // Request MSI interrupt
    err = pci_alloc_irq_vectors(pdev, 1, 1, PCI_IRQ_MSI);
    if (err < 0) return err;

    init_completion(&dev->irq_done);
    spin_lock_init(&dev->lock);

    err = devm_request_irq(&pdev->dev, pci_irq_vector(pdev, 0),
                           djibion_irq, 0, "djibion", dev);
    if (err) return err;

    // Reset device
    iowrite32(CTL_RESET, dev->regs + REG_CONTROL);

    // Create /dev/djibion0
    cdev_init(&dev->cdev, &djibion_fops);
    dev->devno = MKDEV(major, 0);
    cdev_add(&dev->cdev, dev->devno, 1);
    device_create(djibion_class, NULL, dev->devno, dev, "djibion0");

    dev_info(&pdev->dev, "Djibion Neural Accelerator ready, DMA=%dMB\n",
             (int)(dev->dma_size >> 20));
    return 0;
}

static void djibion_remove(struct pci_dev *pdev) {
    struct djibion_dev *dev = pci_get_drvdata(pdev);
    device_destroy(djibion_class, dev->devno);
    cdev_del(&dev->cdev);
    dma_free_coherent(&pdev->dev, dev->dma_size, dev->dma_buf, dev->dma_handle);
}

static const struct pci_device_id djibion_ids[] = {
    { PCI_DEVICE(DJIBION_VENDOR_ID, DJIBION_DEVICE_ID) },
    { 0 }
};
MODULE_DEVICE_TABLE(pci, djibion_ids);

static struct pci_driver djibion_driver = {
    .name     = "djibion",
    .id_table = djibion_ids,
    .probe    = djibion_probe,
    .remove   = djibion_remove,
};

static int __init djibion_init(void) {
    int err = alloc_chrdev_region(&(dev_t){0}, 0, 1, "djibion");
    major = MAJOR((dev_t){0});
    djibion_class = class_create(THIS_MODULE, "djibion");
    return pci_register_driver(&djibion_driver);
}

static void __exit djibion_exit(void) {
    pci_unregister_driver(&djibion_driver);
    class_destroy(djibion_class);
    unregister_chrdev_region(MKDEV(major, 0), 1);
}

module_init(djibion_init);
module_exit(djibion_exit);

MODULE_LICENSE("GPL");
MODULE_AUTHOR("Djiby Diop");
MODULE_DESCRIPTION("Djibion Neural Accelerator PCIe Driver");
```
This driver exposes the D+ hardware accelerator to Linux via `/dev/djibion0` with DMA and MSI interrupts.
